import { Hono } from 'hono';
import { serveStatic } from 'hono/static';
import { createClient } from '@supabase/supabase-js';
import { v4 as uuidv4 } from 'uuid';

const app = new Hono();

// Configure Supabase client
const supabaseUrl = process.env.SUPABASE_URL || 'https://your-supabase-url.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || 'your-anon-key';
const supabaseClient = createClient(supabaseUrl, supabaseAnonKey);

// Configure object storage
const storageBucketName = process.env.STORAGE_BUCKET_NAME || 'your-storage-bucket-name';

app.post('/upload', async (c) => {
  const maxSizeInBytes = 10 * 1024 * 1024; // 10MB
  const allowedMimeTypes = ['image/jpeg', 'image/png'];

  const form = await c.req.parseForm({ type: 'multipart/form-data' });
  const file = form.file;

  if (!file) {
    return c.json({ error: 'No file provided' }, 400);
  }

  // Validate file size
  if (file.size > maxSizeInBytes) {
    return c.json({ error: 'File size exceeds limit' }, 413);
  }

  // Validate mime type
  if (!allowedMimeTypes.includes(file.mimetype)) {
    return c.json({ error: 'Invalid file type' }, 400);
  }

  try {
    // Upload file to object storage
    const response = await supabaseClient.storage.from(storageBucketName).upload(`files/${uuidv4()}`, file.file, {
      upsert: false,
      cacheControl: '3600',
      contentType: file.mimetype,
    });

    if (response.error) {
      return c.json({ error: response.error.message }, 500);
    }

    // Insert file metadata into database
    const { data, error } = await supabaseClient.from('files').insert([
      {
        id: response.data.path.split('/').pop(),
        name: file.name,
        size: file.size,
        mime_type: file.mimetype,
      },
    ]);

    if (error) {
      return c.json({ error: error.message }, 500);
    }

    return c.json({ fileId: data[0].id });
  } catch (error) {
    console.error(error);
    return c.json({ error: 'Internal server error' }, 500);
  }
});

app.use('/static/*', serveStatic({ root: './public' }));

export default app;

